mapper.insert:
insert into user_order_event_outbox(
    event_id, message_id, exchange_name, routing_key, payload_json, status, attempt_count,
    next_retry_time, last_error, published_time, create_time, update_time
)
values(
    #{eventId}, #{messageId}, #{exchangeName}, #{routingKey}, #{payloadJson}, #{status}, #{attemptCount},
    #{nextRetryTime}, #{lastError}, #{publishedTime}, #{createTime}, #{updateTime}
)

mapper.select:
select 
from user_order_event_outbox
where status in ('PENDING', 'FAILED')
  and next_retry_time <= #{now}
  and attempt_count < #{maxAttempts}
order by next_retry_time asc, id asc
limit #{limit}
